const DEFAULT_TEAM_ROSTER = HFB_GROUPS.reduce((acc, g) => {
  const names = SEED_TEAM_ROSTER_NAMES[g.id] || [];
  acc[g.id] = names.map((name, idx) => ({ id: `cw_${g.id}_${idx}`, name }));
  return acc;
}, {});

// True if a stored roster has no names anywhere yet (e.g. it was saved back when the app
// first seeded an empty roster) — in that case it's still safe to apply the seed above.
function isTeamRosterEmpty(raw) {
  if (!raw) return true;
  return HFB_GROUPS.every((g) => !Array.isArray(raw[g.id]) || raw[g.id].length === 0);
}

// Ensure every current HFB group has an entry, even if the stored roster predates a group being added
function migrateTeamRoster(raw) {
  const next = {};
  HFB_GROUPS.forEach((g) => {
    next[g.id] = raw && Array.isArray(raw[g.id]) ? raw[g.id] : [];
  });
  return next;
}

// Resolve which spots belong to a given dashboard scope
function getSpotsForScope(scopeId, spotsConfig) {
  if (scopeId === "overall") return spotsConfig;
  if (scopeId === "showroom" || scopeId === "markethall" || scopeId === "selfserve") {
    return spotsConfig.filter((s) => s.zone === scopeId);
  }
  const group = HFB_GROUPS.find((g) => g.id === scopeId);
  if (!group) return [];
  return spotsConfig.filter((s) => group.spotIds.includes(s.id));
}


