/* ===================== WEEKDAY / WEEKEND HELPERS ===================== */
// Returns "weekend" for Sat/Sun, otherwise "weekday"
function getDayType(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  const dow = d.getDay(); // 0 = Sun, 6 = Sat
  return dow === 0 || dow === 6 ? "weekend" : "weekday";
}

// Migrate an old flat time-slots array into the { weekday, weekend } shape
function migrateTimeSlots(raw) {
  if (raw && !Array.isArray(raw) && (raw.weekday || raw.weekend)) {
    return {
      weekday: raw.weekday && raw.weekday.length > 0 ? raw.weekday : DEFAULT_TIME_SLOTS.weekday,
      weekend: raw.weekend && raw.weekend.length > 0 ? raw.weekend : DEFAULT_TIME_SLOTS.weekend,
    };
  }
  if (Array.isArray(raw) && raw.length > 0) {
    return { weekday: raw, weekend: raw };
  }
  return DEFAULT_TIME_SLOTS;
}

// Migrate an old flat spot ({x,y}) into the per-day-type pos shape
function migrateSpotsConfig(raw) {
  if (!raw || !Array.isArray(raw)) return SPOTS;
  return raw.map((s) => {
    if (s.pos && s.pos.weekday && s.pos.weekend) return s;
    const x = typeof s.x === "number" ? s.x : 50;
    const y = typeof s.y === "number" ? s.y : 50;
    return {
      id: s.id,
      label: s.label,
      zone: s.zone,
      pos: {
        weekday: { default: { x, y }, slots: {} },
        weekend: { default: { x, y }, slots: {} },
      },
    };
  });
}

// Resolve the {x,y} position of a spot for a given day type + time-slot index
function getSpotPos(spot, dayType, slotIdx) {
  const p = spot.pos && spot.pos[dayType];
  if (!p) return { x: 50, y: 50 };
  const slotOverride = p.slots && p.slots[slotIdx];
  if (slotOverride) return slotOverride;
  return p.default || { x: 50, y: 50 };
}

// Backward-compatible helper: returns "yes", "no", or "" from either old string or new object format
function getSellingVerdict(activeSelling) {
  if (!activeSelling) return "";
  if (typeof activeSelling === "string") return activeSelling;
  return activeSelling.verdict || "";
}

