// Sunday-start week key/label, e.g. week of Sun 13 Jul – Sat 19 Jul 2026 -> key "2026-07-13"
function sundayWeekKey(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  const start = new Date(d);
  start.setDate(d.getDate() - d.getDay()); // back up to Sunday
  return `${start.getFullYear()}-${String(start.getMonth() + 1).padStart(2, "0")}-${String(start.getDate()).padStart(2, "0")}`;
}

function sundayWeekLabel(weekKey) {
  const start = new Date(weekKey + "T00:00:00");
  const end = new Date(start);
  end.setDate(start.getDate() + 6);
  const fmtStart = start.toLocaleDateString("en-US", { day: "numeric", month: "short" });
  const fmtEnd = end.toLocaleDateString("en-US", { day: "numeric", month: "short", year: "numeric" });
  return `${fmtStart} – ${fmtEnd}`;
}

function monthKey(dateStr) {
  return dateStr.slice(0, 7); // YYYY-MM
}

function monthLabel(mKey) {
  const [y, m] = mKey.split("-").map(Number);
  return new Date(y, m - 1, 1).toLocaleDateString("en-US", { month: "short", year: "numeric" });
}

function dateLabelShort(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  return d.toLocaleDateString("en-US", { weekday: "short", day: "numeric", month: "short" });
}

// IKEA physical/fiscal year: 1 September – 31 August
function getFiscalYearRange(today = new Date()) {
  const y = today.getFullYear();
  const startYear = today.getMonth() >= 8 ? y : y - 1; // Sep = month index 8
  const start = new Date(startYear, 8, 1);
  const end = new Date(startYear + 1, 7, 31);
  const toKey = (d) => `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
  const fmt = (d) => d.toLocaleDateString("en-US", { day: "numeric", month: "short", year: "numeric" });
  return { startKey: toKey(start), endKey: toKey(end), label: `${fmt(start)} – ${fmt(end)}` };
}

// Restrict a single day's check data down to one round (time-slot index) only —
// lets the existing multi-round stat functions be reused unchanged for a single round.
function pickSlotData(dayChecks, slotIdx) {
  const out = {};
  Object.keys(dayChecks || {}).forEach((spotId) => {
    const rec = dayChecks[spotId]?.[slotIdx];
    if (rec) out[spotId] = { 0: rec };
  });
  return out;
}

